#include <cstdarg>
#include <iostream>

int sumInts(int count, ...)
{
    va_list args;
    va_start(args, count);
    int total{ 0 };
    for (int i{ 0 }; i < count; ++i)
        total += va_arg(args, int);
    va_end(args);
    return total;
}

int main()
{
    int n{};
    std::cin >> n;

    int v[5]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    int result{};
    if (n == 1)
        result = sumInts(1, v[0]);
    else if (n == 2)
        result = sumInts(2, v[0], v[1]);
    else if (n == 3)
        result = sumInts(3, v[0], v[1], v[2]);
    else if (n == 4)
        result = sumInts(4, v[0], v[1], v[2], v[3]);
    else
        result = sumInts(5, v[0], v[1], v[2], v[3], v[4]);

    std::cout << result << '\n';

    return 0;
}

